#include <stdio.h>
#include <string.h>
#include <openssl/evp.h>
#include <openssl/rsa.h>
#include <openssl/bn.h>

// Constants
#define RSA_BITS 2048
#define SHA256_DIGEST_LENGTH 32

int main() {
    EVP_PKEY *pkey = NULL;
    EVP_PKEY_CTX *pkey_ctx = NULL;
    size_t data_len;
    int64_t signature_len;
    unsigned int key_len;
    unsigned char *signature = NULL;
    unsigned char *digest = NULL;
    BIGNUM *modulus_bn = NULL;

    // 1. Generate 2048-bit RSA key using EVP_PKEY_keygen()
    pkey = EVP_PKEY_new();
    if (!pkey) {
        fprintf(stderr, "Error creating EVP_PKEY object.\n");
        return 1;
    }

    // Setup context for key generation
    pkey_ctx = EVP_PKEY_CTX_new(pkey, NULL);
    if (!pkey_ctx) {
        fprintf(stderr, "Error creating EVP_PKEY_CTX.\n");
        EVP_PKEY_free(pkey);
        return 1;
    }

    // Specify RSA algorithm
    if (EVP_PKEY_keygen_init(pkey_ctx) <= 0) {
        fprintf(stderr, "Error initializing keygen.\n");
        EVP_PKEY_CTX_free(pkey_ctx);
        EVP_PKEY_free(pkey);
        return 1;
    }

    // Set the RSA type (OpenSSL 3.0 recommends specifying the algorithm)
    if (EVP_PKEY_CTX_set_rsa_type(pkey_ctx, EVP_PKEY_RSA) <= 0) {
        fprintf(stderr, "Error setting RSA type.\n");
        EVP_PKEY_CTX_free(pkey_ctx);
        EVP_PKEY_free(pkey);
        return 1;
    }

    // Set the key size
    if (EVP_PKEY_CTX_set_rsa_size(pkey_ctx, RSA_BITS) <= 0) {
        fprintf(stderr, "Error setting RSA size.\n");
        EVP_PKEY_CTX_free(pkey_ctx);
        EVP_PKEY_free(pkey);
        return 1;
    }

    // Generate the key
    if (1 != EVP_PKEY_keygen(pkey, &signature)) {
        fprintf(stderr, "Error generating RSA key.\n");
        EVP_PKEY_CTX_free(pkey_ctx);
        EVP_PKEY_free(pkey);
        return 1;
    }

    printf("Successfully generated %d-bit RSA key.\n", RSA_BITS);

    // 3. Extract the modulus n as a BIGNUM
    // EVP_PKEY_get0_rsa() returns a const pointer to the RSA key structure.
    const RSA *rsa = EVP_PKEY_get0_RSA(pkey);
    if (!rsa) {
        fprintf(stderr, "Failed to retrieve RSA structure.\n");
        EVP_PKEY_free(pkey);
        return 1;
    }

    modulus_bn = RSA_get0_d2i(rsa->n, NULL);
    if (!modulus_bn) {
        fprintf(stderr, "Failed to extract modulus n as BIGNUM.\n");
        EVP_PKEY_free(pkey);
        return 1;
    }
    printf("Modulus n successfully extracted as BIGNUM.\n");

    // --- Demonstration of Signing (2) ---

    // Prepare message and digest
    const char *message = "This is the message to be signed by the RSA key.";
    int msg_len = strlen(message);

    // Calculate SHA-256 digest of the message
    digest = EVP_DigestDigest();
    if (!digest) {
        fprintf(stderr, "Error initializing digest.\n");
        EVP_PKEY_free(pkey);
        return 1;
    }

    // Calculate SHA-256 hash of the message
    EVP_DigestInit(digest, EVP_sha256(), NULL);
    EVP_DigestUpdate(digest, message, msg_len);

    // Finalize digest to get the actual digest bytes
    EVP_DigestFinal(digest, NULL);

    // Prepare context for signing
    EVP_MD_CTX *mdctx = NULL;
    if (!EVP_DigestSignInit(&mdctx, NULL, NULL, pkey)) {
        fprintf(stderr, "Error initializing digest signing.\n");
        EVP_PKEY_free(pkey);
        return 1;
    }

    // Perform the signing operation
    if (!EVP_DigestSignUpdate(mdctx, digest, SHA256_DIGEST_LENGTH)) {
        fprintf(stderr, "Error updating digest signing.\n");
        EVP_DigestSignFinal(mdctx, NULL, NULL);
        EVP_PKEY_free(pkey);
        return 1;
    }

    if (!EVP_DigestSignFinal(mdctx, NULL, &signature_len)) {
        fprintf(stderr, "Error finalizing digest signing.\n");
        EVP_PKEY_free(pkey);
        return 1;
    }

    signature = (unsigned char *)malloc(signature_len);
    if (!signature) {
        fprintf(stderr, "Memory allocation failed for signature.\n");
        EVP_PKEY_free(pkey);
        return 1;
    }

    if (EVP_DigestSignFinal(mdctx, signature, &signature_len) <= 0) {
        fprintf(stderr, "Error performing final digest signing.\n");
        free(signature);
        EVP_PKEY_free(pkey);
        return 1;
    }

    printf("Successfully signed SHA-256 digest. Signature length: %ld bytes.\n", signature_len);
    printf("First 16 bytes of signature: ");
    for(unsigned int i = 0; i < (signature_len > 16 ? 16 : signature_len); i++) {
        printf("%02x", signature[i]);
    }
    printf("\n");


    // Cleanup
    EVP_PKEY_free(pkey);
    if (modulus_bn) BN_free(modulus_bn);
    if (signature) free(signature);

    return 0;
}
