#include <openssl/evp.h>
#include <openssl/mac.h>
#include <openssl/err.h>
#include <openssl/param.h>

// Assume 'msg' is the data to be HMAC'd
unsigned char msg[] = "This is the message to be authenticated.";
size_t msg_len = sizeof(msg) - 1;

// --- 1. Define parameters for HMAC (Key and Digest) ---

// Key (e.g., 32 bytes for SHA256 key length)
unsigned char key[32] = {0xAA, 0xBB, 0xCC, 0xDD, 0xEE, 0xFF, 0x11, 0x22, 0x33, 0x44, 0x55, 0x66, 0x77, 0x88, 0x99, 0x00, 0x11, 0x22, 0x33, 0x44, 0x55, 0x66, 0x77, 0x88, 0x99, 0x00, 0xAA, 0xBB, 0xCC, 0xDD};

// Digest identifier (SHA256)
const EVP_MD *digest = EVP_sha256();

// --- 2. Context and Initialization ---

// Create a context for MAC operations
EVP_MAC_CTX *mac_ctx = NULL;

// Initialize the MAC context (setting up the operation for the specific algorithm)
mac_ctx = EVP_MAC_CTX_new();
if (!mac_ctx) {
    // Handle error
    ERR_print_errors_fp(stderr);
    return -1;
}

// Initialize the MAC context using OSSL_PARAM to set the key and digest
// Note: The exact usage of OSSL_PARAM for EVP_MAC depends on the specific OpenSSL version's implementation details.
// In modern OpenSSL, this often involves setting parameters specific to the MAC context.

int ret = EVP_MAC_init(mac_ctx, digest, key);
if (ret != 1) {
    fprintf(stderr, "EVP_MAC_init failed: %d\n", ret);
    EVP_MAC_CTX_free(mac_ctx);
    return -1;
}

// --- 3. Update ---

// Update the MAC context with the message data
size_t len = EVP_MAC_update(mac_ctx, msg, msg_len);
if (len != msg_len) {
    fprintf(stderr, "EVP_MAC_update failed: length mismatch\n");
    EVP_MAC_CTX_free(mac_ctx);
    return -1;
}

// --- 4. Finalize and Fetch ---

unsigned char mac_result[EVP_MAX_MD_SIZE];
size_t mac_len = 0;

// Finalize the MAC operation and retrieve the result
ret = EVP_MAC_final(mac_ctx, mac_result, &mac_len);
if (ret != 1) {
    fprintf(stderr, "EVP_MAC_final failed: %d\n", ret);
    EVP_MAC_CTX_free(mac_ctx);
    return -1;
}

// mac_result now contains the HMAC-SHA256 of 'msg' using 'key'
// mac_len contains the length of the resulting MAC.

printf("Successfully computed HMAC-SHA256.\n");
printf("MAC Result (Hex): ");
for (size_t i = 0; i < mac_len; i++) {
    printf("%02x", mac_result[i]);
}
printf("\n");

// Cleanup
EVP_MAC_CTX_free(mac_ctx);
